public class TestThrottlingScheduler { private static final long MAX_NANOS = Long . MAX_VALUE ; private static final Runnable NO_OP = new Runnable ( ) { @ Override public void run ( ) { } } ; private HighResolutionClock clock ; private ScheduledExecutorService scheduledExecutorService ; private ThrottlingScheduler throttler ; @ Before public void setUp ( ) { clock = Mockito . mock ( HighResolutionClock . class ) ; scheduledExecutorService = Mockito . mock ( ScheduledExecutorService . class ) ; throttler = new ThrottlingScheduler ( MAX_NANOS , scheduledExecutorService , clock ) ; } @ Test public void testInitialState ( ) { ThrottlingExecutor throttler = new ThrottlingExecutor ( MAX_NANOS ) ; assertEquals ( 0 , throttler . getPendingNanos ( ) ) ; assertEquals ( 1.0 , throttler . getWorkFactor ( ) ) ; } @ Test public void testSetWorkRate ( ) { throttler . setWorkFactor ( 1.0 ) ; assertEquals ( 1.0 , throttler . getWorkFactor ( ) ) ; throttler . setWorkFactor ( 0.5 ) ; assertEquals ( 0.5 , throttler . getWorkFactor ( ) ) ; throttler . setWorkFactor ( Throttleable . MIN_WORK_FACTOR ) ; assertEquals ( Throttleable . MIN_WORK_FACTOR , throttler . getWorkFactor ( ) ) ; } @ Test ( expected = IllegalArgumentException . class ) public void testLessThan0PercentWorkRate ( ) { new ThrottlingExecutor ( MAX_NANOS ) . setWorkFactor ( - 0.1 ) ; } @ Test ( expected = IllegalArgumentException . class ) public void testGreaterThan100PercentWorkRate ( ) { new ThrottlingExecutor ( MAX_NANOS ) . setWorkFactor ( 1.1 ) ; } @ Test public void test100PercentWorkRate ( ) throws InterruptedException { throttler . schedule ( NO_OP , 1000 ) ; assertEquals ( 0L , throttler . getPendingNanos ( ) ) ; Mockito . verify ( scheduledExecutorService , Mockito . never ( ) ) . schedule ( Mockito . any ( Runnable . class ) , Mockito . anyLong ( ) , Mockito . any ( TimeUnit . class ) ) ; } @ Test public void test50PercentWorkRate ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; final long workTimeNanos = TimeUnit . MILLISECONDS . toNanos ( 5 ) ; setActualDelay ( workTimeNanos ) ; throttler . schedule ( NO_OP , workTimeNanos ) ; verifyRequestedDelay ( workTimeNanos ) ; assertEquals ( 0L , throttler . getPendingNanos ( ) ) ; } @ Test public void testMinWorkRate ( ) throws InterruptedException { final double workFactor = Throttleable . MIN_WORK_FACTOR ; throttler . setWorkFactor ( workFactor ) ; double workToDelayFactor = ( 1.0 - workFactor ) / workFactor ; final long workTimeNanos = TimeUnit . MILLISECONDS . toNanos ( 5 ) ; final long delayTimeNanos = ( long ) ( workToDelayFactor * workTimeNanos ) ; setActualDelay ( delayTimeNanos ) ; throttler . schedule ( NO_OP , workTimeNanos ) ; verifyRequestedDelay ( delayTimeNanos ) ; assertEquals ( 0 , throttler . getPendingNanos ( ) ) ; } @ Test public void testDelayOvershoot ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; final long workTimeNanos = TimeUnit . MILLISECONDS . toNanos ( 5 ) ; final long expectedDelayNanos = workTimeNanos ; final long actualDelayNanos = TimeUnit . MILLISECONDS . toNanos ( 6 ) ; setActualDelay ( actualDelayNanos ) ; throttler . schedule ( NO_OP , workTimeNanos ) ; verifyRequestedDelay ( expectedDelayNanos ) ; assertEquals ( expectedDelayNanos - actualDelayNanos , throttler . getPendingNanos ( ) ) ; } @ Test public void testDelayUndershoot ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; final long workTimeNanos = TimeUnit . MILLISECONDS . toNanos ( 5 ) ; final long expectedDelayNanos = workTimeNanos ; final long actualDelayNanos = TimeUnit . MILLISECONDS . toNanos ( 4 ) ; setActualDelay ( actualDelayNanos ) ; throttler . schedule ( NO_OP , workTimeNanos ) ; verifyRequestedDelay ( expectedDelayNanos ) ; assertEquals ( expectedDelayNanos - actualDelayNanos , throttler . getPendingNanos ( ) ) ; } @ Test public void testClampDelayMillis ( ) throws InterruptedException { final long maxDelayMillis = 10 ; final long maxDelayNanos = TimeUnit . MILLISECONDS . toNanos ( maxDelayMillis ) ; ThrottlingScheduler throttler = new ThrottlingScheduler ( maxDelayMillis , scheduledExecutorService , clock ) ; throttler . setWorkFactor ( 0.5 ) ; setActualDelay ( maxDelayNanos ) ; throttler . schedule ( NO_OP , TimeUnit . MILLISECONDS . toNanos ( 100 ) ) ; verifyRequestedDelay ( maxDelayNanos ) ; assertEquals ( 0L , throttler . getPendingNanos ( ) ) ; } @ Test public void testDecreaseWorkFactor ( ) { throttler . setWorkFactor ( 0.5 ) ; throttler . setPendingNanos ( 5000 ) ; throttler . setWorkFactor ( 0.3 ) ; assertEquals ( 5000 , throttler . getPendingNanos ( ) ) ; } @ Test public void testOverflowOfDelayNanos ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; throttler . setPendingNanos ( Long . MAX_VALUE ) ; assertEquals ( Long . MAX_VALUE , throttler . getPendingNanos ( ) ) ; long workDurationNs = 5000 ; setActualDelay ( workDurationNs ) ; throttler . schedule ( NO_OP , workDurationNs ) ; verifyRequestedDelay ( workDurationNs ) ; assertEquals ( Long . MAX_VALUE - workDurationNs , throttler . getPendingNanos ( ) ) ; } @ Test public void testNegativePendingNanos ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; throttler . setPendingNanos ( - 1000 ) ; assertEquals ( - 1000 , throttler . getPendingNanos ( ) ) ; throttler . schedule ( NO_OP , 500 ) ; Mockito . verify ( scheduledExecutorService , Mockito . never ( ) ) . schedule ( Mockito . any ( Runnable . class ) , Mockito . anyLong ( ) , Mockito . any ( TimeUnit . class ) ) ; assertEquals ( - 1000 + 500 , throttler . getPendingNanos ( ) ) ; } @ Test public void testNegativePendingNanosGoesPositive ( ) throws InterruptedException { throttler . setWorkFactor ( 0.5 ) ; long startPendingNanos = - 1000 ; throttler . setPendingNanos ( startPendingNanos ) ; assertEquals ( - 1000 , throttler . getPendingNanos ( ) ) ; setActualDelay ( 1250 ) ; throttler . schedule ( NO_OP , 1250 ) ; verifyRequestedDelay ( 1250 ) ; assertEquals ( startPendingNanos , throttler . getPendingNanos ( ) ) ; } private void setActualDelay ( long actualDelayNs ) { Mockito . when ( clock . nanoTime ( ) ) . thenReturn ( 0L ) . thenReturn ( actualDelayNs ) ; } private void verifyRequestedDelay ( long expectedDelayTimeNanos ) throws InterruptedException { ArgumentCaptor < Runnable > runnableCaptor = ArgumentCaptor . forClass ( Runnable . class ) ; Mockito . verify ( scheduledExecutorService ) . schedule ( runnableCaptor . capture ( ) , Mockito . eq ( expectedDelayTimeNanos ) , Mockito . eq ( TimeUnit . NANOSECONDS ) ) ; runnableCaptor . getValue ( ) . run ( ) ; } }